  showConfirm(message, confirmText, onConfirm) {
    const width = this.cameras.main.width;
    const height = this.cameras.main.height;
    this.confirmContainer = this.add.container(width / 2, height / 2).setDepth(300);
    this.confirmContainer.add(this.add.rectangle(0, 0, width, height, 0x000000, 0.45)
      .setInteractive());
    this.confirmContainer.add(this.add.rectangle(0, 0, 420, 180, WARM_UI.panel, 0.98)
      .setStrokeStyle(3, WARM_UI.gold));
    this.confirmContainer.add(this.add.text(0, -40, message, {
      fontSize: '18px',
      fontFamily: 'Georgia, serif',
      color: WARM_UI.text,
      align: 'center',
      wordWrap: { width: 360, useAdvancedWrap: true }
    }).setOrigin(0.5));

    const confirmButton = this.createButton(-90, 48, confirmText, onConfirm, WARM_UI.button);
    const cancelButton = this.createButton(90, 48, '鍙栨秷', () => this.hideConfirm(), WARM_UI.warning);
    this.confirmContainer.add([confirmButton, cancelButton]);
  }

  hideConfirm() {
    if (!this.confirmContainer) return;
    this.confirmContainer.destroy();
    this.confirmContainer = null;
  }

  closeScene(forceReturnScene = null) {
    this.hideConfirm();
    window.gameState.setGameState(GAME_STATE.NORMAL);
    const target = forceReturnScene || this.returnScene;
    this.scene.start(target);
  }

  createButton(x, y, text, callback, color = WARM_UI.button) {
    const btn = this.add.container(x, y);
    const bg = this.add.rectangle(0, 0, 130, 38, color, 0.92)
      .setStrokeStyle(2, WARM_UI.buttonHover)
      .setInteractive({ useHandCursor: true });
    const label = this.add.text(0, 0, text, {
      fontSize: '15px',
      fontFamily: 'Georgia, serif',
      color: WARM_UI.text
    }).setOrigin(0.5);
    btn.add([bg, label]);

    bg.on('pointerover', () => {
      if (btn.getData('disabled')) return;
      bg.setAlpha(1);
    });
    bg.on('pointerout', () => bg.setAlpha(btn.getData('disabled') ? 0.35 : 0.92));
    bg.on('pointerdown', () => {
      if (btn.getData('disabled')) return;
      callback();
    });
    return btn;
  }

  setButtonEnabled(button, enabled) {
    button.setData('disabled', !enabled);
    button.setAlpha(enabled ? 1 : 0.35);
  }

  showToast(message, duration = 1500) {
    if (this.toast) this.toast.destroy();
    this.toast = this.add.container(this.cameras.main.width / 2, 38).setDepth(400);
    this.toast.add(this.add.rectangle(0, 0, 360, 46, WARM_UI.panel, 0.98)
      .setStrokeStyle(2, WARM_UI.alchemy));
    this.toast.add(this.add.text(0, 0, message, {
      fontSize: '16px',
      fontFamily: 'Georgia, serif',
      color: WARM_UI.alchemyText
    }).setOrigin(0.5));

    this.tweens.add({
      targets: this.toast,
      alpha: 0,
      y: this.toast.y - 24,
      duration,
      ease: 'Power2',
      onComplete: () => {
        if (this.toast) {
          this.toast.destroy();
          this.toast = null;
        }
      }
    });
  }

  formatClock(hour, minute) {
    return `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
  }

  formatSavedAt(value) {
    if (!value) return '鏈煡';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    const yyyy = date.getFullYear();
    const mm = String(date.getMonth() + 1).padStart(2, '0');
    const dd = String(date.getDate()).padStart(2, '0');
    const hh = String(date.getHours()).padStart(2, '0');
    const mi = String(date.getMinutes()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd} ${hh}:${mi}`;
  }
}

